@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container" @ref="_containerRef">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="infinite-scroll-sentinel">
            @if (_loading)
            {
                <div class="d-flex justify-content-center py-3">
                    <div class="spinner-border" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    /// <summary>The collection of items to display.</summary>
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    /// <summary>Whether more items are available to load.</summary>
    [Parameter]
    public bool HasMore { get; set; }

    /// <summary>Callback invoked when more items should be loaded.</summary>
    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    /// <summary>Template for rendering each item.</summary>
    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    private ElementReference _containerRef;
    private ElementReference _sentinelRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _dotNetRef;
    private bool _loading;
    private bool _observerAttached;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-e2db85088fcb4811818877b4a259a9b4/infinite-scroll.js");
            _dotNetRef = DotNetObjectReference.Create(this);
        }

        if (HasMore && !_observerAttached && _module is not null)
        {
            await _module.InvokeVoidAsync("observe", _sentinelRef, _dotNetRef);
            _observerAttached = true;
        }
        else if (!HasMore && _observerAttached && _module is not null)
        {
            await _module.InvokeVoidAsync("disconnect");
            _observerAttached = false;
        }
    }

    [JSInvokable]
    public async Task OnIntersecting()
    {
        if (_loading || !HasMore)
            return;

        _loading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        _loading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("disconnect");
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit may already be gone during disposal.
            }
        }
        _dotNetRef?.Dispose();
    }
}

let observer = null;

export function observe(sentinelElement, dotNetRef) {
    disconnect();

    observer = new IntersectionObserver((entries) => {
        for (const entry of entries) {
            if (entry.isIntersecting) {
                dotNetRef.invokeMethodAsync('OnIntersecting');
            }
        }
    }, { rootMargin: '0px 0px 128px 0px' });

    observer.observe(sentinelElement);
}

export function disconnect() {
    if (observer) {
        observer.disconnect();
        observer = null;
    }
}

